const { execSync } = require('child_process');
const fs = require('fs');

const CHROME_EPOCH_OFFSET_US = 11644473600000000;
const TAIPEI_OFFSET_MS = 8 * 60 * 60 * 1000;

const now = new Date();
const taipeiNow = new Date(now.getTime() + TAIPEI_OFFSET_MS);
const y = taipeiNow.getUTCFullYear();
const m = taipeiNow.getUTCMonth();
const d = taipeiNow.getUTCDate();

const startUtcMs = Date.UTC(y, m, d, 0, 0, 0) - TAIPEI_OFFSET_MS;
const endUtcMs = startUtcMs + 24 * 60 * 60 * 1000;

const startChrome = startUtcMs * 1000 + CHROME_EPOCH_OFFSET_US;
const endChrome = endUtcMs * 1000 + CHROME_EPOCH_OFFSET_US;

const sources = [
  { name: 'chrome', src: '/data/chrome/History', tmp: '/tmp/chrome_history_copy.db' },
  { name: 'edge', src: '/data/edge/History', tmp: '/tmp/edge_history_copy.db' },
  { name: 'chrome', src: '/data/new_pc/chrome_History', tmp: '/tmp/new_pc_chrome_history_copy.db' },
  { name: 'edge', src: '/data/new_pc/edge_History', tmp: '/tmp/new_pc_edge_history_copy.db' },
];

const results = [];

for (const { name, src, tmp } of sources) {
  try {
    fs.copyFileSync(src, tmp);
    const sql = `SELECT url, title, last_visit_time, visit_count FROM urls WHERE last_visit_time BETWEEN ${startChrome} AND ${endChrome} ORDER BY last_visit_time DESC`;
    const output = execSync(`sqlite3 -json "${tmp}" "${sql}"`, { encoding: 'utf8', maxBuffer: 1024 * 1024 * 20 });
    const rows = output.trim() ? JSON.parse(output) : [];
    for (const row of rows) {
      results.push({
        json: {
          source: name,
          url: row.url,
          title: row.title,
          visitCount: row.visit_count,
          lastVisitTime: new Date((row.last_visit_time - CHROME_EPOCH_OFFSET_US) / 1000).toISOString(),
        },
      });
    }
  } catch (err) {
    results.push({ json: { source: name, _error: String(err.message || err) } });
  } finally {
    if (fs.existsSync(tmp)) fs.unlinkSync(tmp);
  }
}

return results;

const fs = require('fs');

let blacklistDomains = [];
try {
  const raw = fs.readFileSync('/config/domain_blacklist.json', 'utf8');
  const data = JSON.parse(raw);
  for (const key of Object.keys(data)) {
    if (key.startsWith('_')) continue;
    if (Array.isArray(data[key])) blacklistDomains.push(...data[key]);
  }
} catch (err) {
  // no blacklist file -> no exclusions
}

const items = $input.all();
const merged = new Map();

for (const item of items) {
  const { url, title, visitCount, lastVisitTime, source, _error } = item.json;
  if (_error) continue;
  if (!url) continue;
  if (blacklistDomains.some((domain) => domain && url.includes(domain))) continue;

  let category = 'article';
  let videoId = null;

  const watchMatch = url.match(/[?&]v=([a-zA-Z0-9_-]{11})/);
  const shortMatch = url.match(/youtu\.be\/([a-zA-Z0-9_-]{11})/);
  if (url.includes('youtube.com/watch') && watchMatch) {
    category = 'youtube';
    videoId = watchMatch[1];
  } else if (url.includes('youtu.be/') && shortMatch) {
    category = 'youtube';
    videoId = shortMatch[1];
  }

  const existing = merged.get(url);
  if (existing) {
    existing.visitCount += visitCount || 0;
    existing.sources = Array.from(new Set([...existing.sources, source]));
    if (lastVisitTime > existing.lastVisitTime) existing.lastVisitTime = lastVisitTime;
  } else {
    merged.set(url, {
      category,
      videoId,
      url,
      title,
      visitCount: visitCount || 0,
      lastVisitTime,
      sources: [source],
    });
  }
}

return Array.from(merged.values())
  .sort((a, b) => (a.lastVisitTime < b.lastVisitTime ? 1 : -1))
  .map((json) => ({ json }));
